module gray_code_counter_6 
(
  input rst,
  input clk,

  output reg [5:0] count
);

  reg [5:0] gray_code;

  always @(posedge clk or posedge rst) begin
    if (rst) 
	begin
      gray_code <= 6'b000000;
      count <= 6'b000000;
    end 
	else 
	begin
      gray_code <= gray_code + 1;
      count <= (gray_code >> 1) ^ gray_code;
    end
  end

endmodule
